mapper.select:
SELECT p.partner_id AS memberId, m.login_id AS loginId, m2.nickname AS nickname, TO_CHAR(o.order_date, 'YYYY-MM') AS settlementMonth, COUNT(DISTINCT pl.place_id) AS placeCount,
/* 총 결제액 : 결제완료·체크아웃완료 주문 기준 */ NVL(SUM(o.real_total_amount), 0) AS totalGmv,
/* 수수료 : 파트너 commission_rate 적용 */ NVL(SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)), 0) AS totalCommission,
/* 쿠폰 파트너 부담 — coupon_usage.partner_discount_amount */ NVL(SUM(cu.partner_discount_amount), 0) AS totalCouponPartner,
/* 최종 지급액 */ NVL(SUM(o.real_total_amount) - SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)) - SUM(NVL(cu.partner_discount_amount, 0)), 0) AS totalNetPayout,
/* 정산 상태 집계 */ CASE WHEN COUNT(DISTINCT pl.place_id) = SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END) THEN 'done' WHEN SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END) > 0 THEN 'partial' ELSE 'pending' END AS settlementStatus,
SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END) AS approvedPlaceCount,
MAX(p.commission_rate) AS commissionRate,
SUM(CASE WHEN rv.check_out_date < TRUNC(SYSDATE) THEN 1 ELSE 0 END) AS checkedOutCount, COUNT(rv.reservation_id) AS totalReservationCount
FROM partner p JOIN member1 m ON m.member_id = p.member_id JOIN member2 m2 ON m2.member_id = m.member_id JOIN place pl ON pl.partner_id = p.partner_id JOIN room r ON r.place_id = pl.place_id JOIN reservation rv ON rv.room_id = r.room_id JOIN order_detail od ON od.reservation_id = rv.reservation_id JOIN orders o ON o.order_id = od.order_id LEFT JOIN partner_settlement ps ON ps.partner_id = p.partner_id AND ps.settlement_month = TO_CHAR(o.order_date, 'YYYY-MM') LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'cancelled' WHERE 1=1 AND o.status != 'CANCELED'
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
AND (m.login_id LIKE '%' || #{keyword} || '%' OR m2.nickname LIKE '%' || #{keyword} || '%')
GROUP BY p.partner_id, m.login_id, m2.nickname, TO_CHAR(o.order_date, 'YYYY-MM')
HAVING
COUNT(DISTINCT pl.place_id) = SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END)
SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END) > 0 AND COUNT(DISTINCT pl.place_id) > SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END)
SUM(CASE WHEN ps.status = 'done' THEN 1 ELSE 0 END) = 0
ORDER BY settlementMonth DESC, totalGmv DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT o.order_id, od.reservation_id, o.order_date, guest2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM partner p JOIN place pl ON pl.partner_id = p.partner_id JOIN room r ON r.place_id = pl.place_id JOIN reservation rv ON rv.room_id = r.room_id JOIN order_detail od ON od.reservation_id = rv.reservation_id JOIN orders o ON o.order_id = od.order_id JOIN member1 guest ON guest.member_id = o.member_id JOIN member2 guest2 ON guest2.member_id = guest.member_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'cancelled' LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.partner_id = #{memberId} AND o.status != 'CANCELED'
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY pl.place_id, o.order_date DESC

SELECT o.order_id, od.reservation_id, o.order_date, guest2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM orders o JOIN order_detail od ON od.order_id = o.order_id JOIN reservation rv ON rv.reservation_id = od.reservation_id JOIN room r ON r.room_id = rv.room_id JOIN place pl ON pl.place_id = r.place_id JOIN partner p ON p.partner_id = pl.partner_id JOIN member1 guest ON guest.member_id = o.member_id JOIN member2 guest2 ON guest2.member_id = guest.member_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'cancelled' LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.partner_id = #{partnerId} AND o.status != 'CANCELED'
AND TO_CHAR(o.order_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY o.order_date DESC
